form:Form.form:Scripts:
		var xml, orden;

function OnLoad()
{
	orden=new nomadDOM(ELE2String(Ctrl('main').GetLastDoc('RECIBOS')));
	xml=orden.Child[0];

	refresh();
}

function refresh()
{         
	var t, d, best_mont, best_porc, nd, tot_leg, tot_pag, si_leg, si_pag, leg;

	tot_leg=0; tot_pag=0;           
	si_leg=0;  si_pag=0;



	for (t=0; t<xml.Child.length; t++)
	{              
		leg=xml.Child[t];    
		my_pen=parseFloat(leg.totpen);
		tot_leg++;
		tot_pag+=my_pen;             


		//Inicializo los Recibos		
		for (r=0; r<leg.recibos.Child.length; r++)
		{
			rec=leg.recibos.Child[r];           

			if (rec.totpen=="?")
				rec.associatedELE.setAttribute("totpen",parseFloat(leg.totpen));
		}


		//if ((Ctrl("grd1").RowsCount()!=0) || (Ctrl("grd2").RowsCount()!=0))
		//{
			//Analizo los Porcentajes 
			if (Ctrl("grd1").RowsCount()>0)
			{

				best_mont=-1;
				for (d=0; d<Ctrl("grd1").RowsCount(); d++)
				{        
					val_mont=parseFloat(Ctrl("grd1").GetCellXValue("monto_hasta_porc",d));
					val_porc=parseFloat(Ctrl("grd1").GetCellXValue("porcentaje"      ,d));

					if ((val_mont>my_pen) && (best_mont==-1 || best_mont>val_mont))
					{               
						best_porc=val_porc;
						best_mont=val_mont;
					}
				}  

				if (best_mont!=-1)
				{
					my_pen=Math.round(my_pen*best_porc)/100;
				}
			}

			//Analizo los Montos
			if (Ctrl("grd1").RowsCount()==0 || best_mont!=-1)
			{        
				if (Ctrl("grd2").RowsCount()==0)
				{         
					for (r=0; r<leg.recibos.Child.length; r++)
					{
						rec=leg.recibos.Child[r];

						if (rec.totpen=="?")
							rec.associatedELE.setAttribute("totpen",(parseFloat(leg.totpen)-my_pen).toString());
					}

					si_leg++;  
					si_pag+=my_pen;
				} else
				{

					best_mont=-1;
					for (d=0; d<Ctrl("grd2").RowsCount(); d++)
					{        
						val_mont=parseFloat(Ctrl("grd2").GetCellXValue("monto_hasta",d));
						val_tope=parseFloat(Ctrl("grd2").GetCellXValue("monto_tope" ,d));

						if ((val_mont>my_pen) && (best_mont==-1 || best_mont>val_mont))
						{
							best_tope=val_tope;
							best_mont=val_mont;
						}
					}  

					if (best_mont!=-1)                       
					{             
						my_pen=(my_pen>best_tope?best_tope:my_pen);

						for (r=0; r<leg.recibos.Child.length; r++)
						{
							rec=leg.recibos.Child[r];           

							if (rec.totpen=="?")
								rec.associatedELE.setAttribute("totpen",(parseFloat(leg.totpen)-my_pen).toString());
						}

						si_leg++;  
						si_pag+=my_pen;
					}
				}
			}
		//}
	}        



	Ctrl("monto_total").SetTypedValue(tot_pag);
	Ctrl("legajos_total").SetTypedValue(tot_leg);

	Ctrl("monto_pagar").SetTypedValue(si_pag);
	Ctrl("legajos_incluidos").SetTypedValue(si_leg);

	Ctrl("monto_pen").SetTypedValue(tot_pag-si_pag);
	Ctrl("legajos_no_incluidos").SetTypedValue(tot_leg-si_leg);
}      

function SendToServer()
{
	refresh();

	proxy=new NomadProxy();
	NFS=new NomadFileService(proxy,"FILE-IO");

	NFS.SaveFile("TEMP",Ctrl("oi_liquidacion_ddo").GetXValue()+".orden.XML",ELE2String(orden.associatedELE));
}       


function ActualizeXML()
{	
	SendToServer();
	return true;
}


function CONSULTAR()
{
	ActualizeXML();
	if (Ctrl("legajos_incluidos").GetCValue()<=0)
	{
		alert("No hay legajos incluídos en la Orden de Pago.");
		return;
	}
	openNewFlow("NucleusRH.Base.Tesoreria.OrdenesPago.flow", "vista_previa", "<DATOS ID=\""+Ctrl('oi_liquidacion_ddo').GetXValue()+"\" />", null, "L");
}

function validate(me)
{
	if (Ctrl("f_cierre").GetXValue()=="")
	{
		me.SetError("La liquidación debe estar cerrada.");
		return false;
	}
	if (Ctrl("legajos_incluidos").GetCValue()<=0)
	{
		me.SetError("No hay legajos incluídos en la Orden de Pago.");
		return false;
	}
	ActualizeXML();
	return true;
}
